// ROME-TAG: 0xD1AG-WR
import * as fs from 'node:fs';
import * as path from 'node:path';
import logger from '../utils/logger.js';
export function writeDiagnostics(diag) {
    try {
        const dir = path.join(process.cwd(), '.qflush');
        if (!fs.existsSync(dir))
            fs.mkdirSync(dir, { recursive: true });
        const file = path.join(dir, 'diagnostics.json');
        fs.writeFileSync(file, JSON.stringify(diag, null, 2), 'utf8');
        logger.info(`🩺 QFLUSH diagnostics written → .qflush/diagnostics.json`);
    }
    catch (e) {
        logger.warn('Failed to write diagnostics: ' + String(e));
    }
}
